// HTML structure
/*
<div id="app">
  <h1>Todo List</h1>
  <div class="input-container">
    <input type="text" id="todoInput" placeholder="Add a new todo...">
    <button id="addBtn">Add</button>
  </div>
  <ul id="todoList"></ul>
  <div class="stats">
    <span>Total: <span id="totalCount">0</span></span>
    <span>Completed: <span id="completedCount">0</span></span>
  </div>
</div>
*/

// JavaScript
class TodoApp {
  constructor() {
    this.todos = JSON.parse(localStorage.getItem('todos')) || [];
    this.initializeElements();
    this.render();
    this.setupEventListeners();
  }

  initializeElements() {
    this.todoInput = document.getElementById('todoInput');
    this.addBtn = document.getElementById('addBtn');
    this.todoList = document.getElementById('todoList');
    this.totalCount = document.getElementById('totalCount');
    this.completedCount = document.getElementById('completedCount');
  }

  setupEventListeners() {
    this.addBtn.addEventListener('click', () => this.addTodo());
    this.todoInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.addTodo();
    });
  }

  addTodo() {
    const text = this.todoInput.value.trim();
    if (!text) return;

    const todo = {
      id: Date.now(),
      text,
      completed: false,
      createdAt: new Date()
    };

    this.todos.push(todo);
    this.saveTodos();
    this.render();
    this.todoInput.value = '';
    this.todoInput.focus();
  }

  toggleTodo(id) {
    this.todos = this.todos.map(todo => 
      todo.id === id ? { ...todo, completed: !todo.completed } : todo
    );
    this.saveTodos();
    this.render();
  }

  deleteTodo(id) {
    this.todos = this.todos.filter(todo => todo.id !== id);
    this.saveTodos();
    this.render();
  }

  saveTodos() {
    localStorage.setItem('todos', JSON.stringify(this.todos));
  }

  render() {
    this.todoList.innerHTML = '';

    this.todos.forEach(todo => {
      const li = document.createElement('li');
      li.className = todo.completed ? 'completed' : '';

      li.innerHTML = `
        <input type="checkbox" ${todo.completed ? 'checked' : ''}>
        <span>${todo.text}</span>
        <button class="delete-btn">×</button>
      `;

      const checkbox = li.querySelector('input[type="checkbox"]');
      checkbox.addEventListener('change', () => this.toggleTodo(todo.id));

      const deleteBtn = li.querySelector('.delete-btn');
      deleteBtn.addEventListener('click', () => this.deleteTodo(todo.id));

      this.todoList.appendChild(li);
    });

    this.updateStats();
  }

  updateStats() {
    const total = this.todos.length;
    const completed = this.todos.filter(todo => todo.completed).length;

    this.totalCount.textContent = total;
    this.completedCount.textContent = completed;
  }
}

// Initialize app
new TodoApp();

// HTML structure
/*
<div class="counter-app">
  <h1>Counter App</h1>
  <div class="counter-display" id="counterValue">0</div>
  <div class="buttons">
    <button id="decrementBtn">-</button>
    <button id="resetBtn">Reset</button>
    <button id="incrementBtn">+</button>
  </div>
  <div class="history">
    <h3>History</h3>
    <ul id="historyList"></ul>
  </div>
</div>
*/

// JavaScript
class CounterApp {
  constructor() {
    this.count = 0;
    this.history = [];
    this.initializeElements();
    this.setupEventListeners();
    this.updateDisplay();
  }

  initializeElements() {
    this.counterValue = document.getElementById('counterValue');
    this.incrementBtn = document.getElementById('incrementBtn');
    this.decrementBtn = document.getElementById('decrementBtn');
    this.resetBtn = document.getElementById('resetBtn');
    this.historyList = document.getElementById('historyList');
  }

  setupEventListeners() {
    this.incrementBtn.addEventListener('click', () => this.increment());
    this.decrementBtn.addEventListener('click', () => this.decrement());
    this.resetBtn.addEventListener('click', () => this.reset());
  }

  increment() {
    this.count++;
    this.addToHistory('Increased');
    this.updateDisplay();
  }

  decrement() {
    this.count--;
    this.addToHistory('Decreased');
    this.updateDisplay();
  }

  reset() {
    this.addToHistory(`Reset from ${this.count} to 0`);
    this.count = 0;
    this.updateDisplay();
  }

  addToHistory(action) {
    const timestamp = new Date().toLocaleTimeString();
    this.history.unshift({
      action,
      value: this.count,
      time: timestamp
    });

    if (this.history.length > 5) {
      this.history.pop();
    }

    this.updateHistory();
  }

  updateDisplay() {
    this.counterValue.textContent = this.count;

    // Change color based on value
    if (this.count > 0) {
      this.counterValue.style.color = 'green';
    } else if (this.count < 0) {
      this.counterValue.style.color = 'red';
    } else {
      this.counterValue.style.color = 'black';
    }

    // Disable decrement button if count is -10 or less
    this.decrementBtn.disabled = this.count <= -10;
  }

  updateHistory() {
    this.historyList.innerHTML = '';

    this.history.forEach(item => {
      const li = document.createElement('li');
      li.textContent = `${item.time}: ${item.action} → ${item.value}`;
      this.historyList.appendChild(li);
    });
  }
}

// Initialize app
new CounterApp();

