/*
<div class="calculator">
  <div class="display">
    <div class="previous-operand" id="previousOperand"></div>
    <div class="current-operand" id="currentOperand">0</div>
  </div>
  <div class="buttons">
    <button class="btn operator" data-action="clear">C</button>
    <button class="btn operator" data-action="delete">DEL</button>
    <button class="btn operator" data-action="percentage">%</button>
    <button class="btn operator" data-action="divide">÷</button>

    <button class="btn number" data-number="7">7</button>
    <button class="btn number" data-number="8">8</button>
    <button class="btn number" data-number="9">9</button>
    <button class="btn operator" data-action="multiply">×</button>

    <button class="btn number" data-number="4">4</button>
    <button class="btn number" data-number="5">5</button>
    <button class="btn number" data-number="6">6</button>
    <button class="btn operator" data-action="subtract">-</button>

    <button class="btn number" data-number="1">1</button>
    <button class="btn number" data-number="2">2</button>
    <button class="btn number" data-number="3">3</button>
    <button class="btn operator" data-action="add">+</button>

    <button class="btn number" data-number="0">0</button>
    <button class="btn number" data-number=".">.</button>
    <button class="btn operator equals" data-action="equals">=</button>
  </div>
</div>
*/

// JavaScript
class Calculator {
  constructor() {
    this.previousOperand = '';
    this.currentOperand = '0';
    this.operation = undefined;
    this.initializeElements();
    this.setupEventListeners();
    this.updateDisplay();
  }

  initializeElements() {
    this.previousOperandElement = document.getElementById('previousOperand');
    this.currentOperandElement = document.getElementById('currentOperand');
    this.buttons = document.querySelectorAll('.btn');
  }

  setupEventListeners() {
    this.buttons.forEach(button => {
      button.addEventListener('click', () => {
        if (button.classList.contains('number')) {
          this.appendNumber(button.getAttribute('data-number'));
        } else if (button.classList.contains('operator')) {
          this.chooseOperation(button.getAttribute('data-action'));
        }
        this.updateDisplay();
      });
    });

    // Keyboard support
    document.addEventListener('keydown', (e) => {
      if (e.key >= '0' && e.key <= '9' || e.key === '.') {
        this.appendNumber(e.key);
      } else if (e.key === '+' || e.key === '-' || e.key === '*' || e.key === '/') {
        const operations = {
          '+': 'add',
          '-': 'subtract',
          '*': 'multiply',
          '/': 'divide'
        };
        this.chooseOperation(operations[e.key]);
      } else if (e.key === 'Enter' || e.key === '=') {
        this.compute();
      } else if (e.key === 'Escape') {
        this.clear();
      } else if (e.key === 'Backspace') {
        this.delete();
      }
      this.updateDisplay();
    });
  }

  appendNumber(number) {
    if (number === '.' && this.currentOperand.includes('.')) return;

    if (this.currentOperand === '0' && number !== '.') {
      this.currentOperand = number;
    } else {
      this.currentOperand += number;
    }
  }

  chooseOperation(action) {
    if (this.currentOperand === '') return;

    if (this.previousOperand !== '') {
      this.compute();
    }

    switch (action) {
      case 'add': this.operation = '+'; break;
      case 'subtract': this.operation = '-'; break;
      case 'multiply': this.operation = '*'; break;
      case 'divide': this.operation = '/'; break;
      case 'percentage': this.operation = '%'; break;
      case 'equals': this.compute(); return;
      case 'clear': this.clear(); return;
      case 'delete': this.delete(); return;
    }

    this.previousOperand = this.currentOperand;
    this.currentOperand = '';
  }

  compute() {
    let computation;
    const prev = parseFloat(this.previousOperand);
    const current = parseFloat(this.currentOperand);

    if (isNaN(prev) || isNaN(current)) return;

    switch (this.operation) {
      case '+': computation = prev + current; break;
      case '-': computation = prev - current; break;
      case '*': computation = prev * current; break;
      case '/': computation = prev / current; break;
      case '%': computation = prev % current; break;
      default: return;
    }

    this.currentOperand = computation.toString();
    this.operation = undefined;
    this.previousOperand = '';
  }

  clear() {
    this.currentOperand = '0';
    this.previousOperand = '';
    this.operation = undefined;
  }

  delete() {
    this.currentOperand = this.currentOperand.toString().slice(0, -1);
    if (this.currentOperand === '') {
      this.currentOperand = '0';
    }
  }

  updateDisplay() {
    this.currentOperandElement.textContent = this.currentOperand;

    if (this.operation != null) {
      this.previousOperandElement.textContent = 
        `${this.previousOperand} ${this.operation}`;
    } else {
      this.previousOperandElement.textContent = '';
    }
  }
}

// Initialize calculator
new Calculator();

// HTML structure
/*
<div class="clock-container">
  <div class="header">
    <h1>Digital Clock</h1>
    <div class="controls">
      <button id="themeToggle">🌙 Dark Mode</button>
      <button id="formatToggle">12H</button>
    </div>
  </div>

  <div class="clock">
    <div class="time" id="time">00:00:00</div>
    <div class="date" id="date">Monday, January 1, 2023</div>
    <div class="day" id="day">Day 1 of 365</div>
  </div>

  <div class="timezone">
    <span id="timezone">Timezone: UTC</span>
  </div>
</div>
*/

// JavaScript
class DigitalClock {
  constructor() {
    this.is24HourFormat = false;
    this.isDarkMode = false;
    this.initializeElements();
    this.setupEventListeners();
    this.updateClock();
    this.startClock();
    this.applyTheme();
  }

  initializeElements() {
    this.timeElement = document.getElementById('time');
    this.dateElement = document.getElementById('date');
    this.dayElement = document.getElementById('day');
    this.timezoneElement = document.getElementById('timezone');
    this.themeToggle = document.getElementById('themeToggle');
    this.formatToggle = document.getElementById('formatToggle');
  }

  setupEventListeners() {
    this.themeToggle.addEventListener('click', () => {
      this.isDarkMode = !this.isDarkMode;
      this.applyTheme();
    });

    this.formatToggle.addEventListener('click', () => {
      this.is24HourFormat = !this.is24HourFormat;
      this.formatToggle.textContent = this.is24HourFormat ? '24H' : '12H';
      this.updateClock();
    });
  }

  updateClock() {
    const now = new Date();

    // Update time
    let hours = now.getHours();
    const minutes = now.getMinutes().toString().padStart(2, '0');
    const seconds = now.getSeconds().toString().padStart(2, '0');

    let timeString;
    if (!this.is24HourFormat) {
      const ampm = hours >= 12 ? 'PM' : 'AM';
      hours = hours % 12 || 12;
      timeString = `${hours.toString().padStart(2, '0')}:${minutes}:${seconds} ${ampm}`;
    } else {
      timeString = `${hours.toString().padStart(2, '0')}:${minutes}:${seconds}`;
    }

    this.timeElement.textContent = timeString;

    // Update date
    const options = { 
      weekday: 'long', 
      year: 'numeric', 
      month: 'long', 
      day: 'numeric' 
    };
    this.dateElement.textContent = now.toLocaleDateString('en-US', options);

    // Update day of year
    const start = new Date(now.getFullYear(), 0, 0);
    const diff = now - start;
    const oneDay = 1000 * 60 * 60 * 24;
    const dayOfYear = Math.floor(diff / oneDay);

    // Check for leap year
    const isLeapYear = (now.getFullYear() % 4 === 0 && 
                       now.getFullYear() % 100 !== 0) || 
                       now.getFullYear() % 400 === 0;
    const totalDays = isLeapYear ? 366 : 365;

    this.dayElement.textContent = `Day ${dayOfYear} of ${totalDays}`;

    // Update timezone
    const timezone = Intl.DateTimeFormat().resolvedOptions().timeZone;
    this.timezoneElement.textContent = `Timezone: ${timezone}`;
  }

  startClock() {
    // Update immediately
    this.updateClock();

    // Update every second
    setInterval(() => {
      this.updateClock();
    }, 1000);
  }

  applyTheme() {
    const body = document.body;

    if (this.isDarkMode) {
      body.classList.add('dark-mode');
      this.themeToggle.textContent = '☀️ Light Mode';
      this.themeToggle.style.backgroundColor = '#333';
      this.themeToggle.style.color = '#fff';
    } else {
      body.classList.remove('dark-mode');
      this.themeToggle.textContent = '🌙 Dark Mode';
      this.themeToggle.style.backgroundColor = '#f0f0f0';
      this.themeToggle.style.color = '#333';
    }
  }
}

