// HTML structure
/*
<div class="weather-app">
  <div class="header">
    <h1>Weather App</h1>
    <div class="search-container">
      <input type="text" id="cityInput" placeholder="Enter city name...">
      <button id="searchBtn">Search</button>
      <button id="locationBtn">📍</button>
      <button id="unitToggle">°C / °F</button>
    </div>
  </div>

  <div class="current-weather" id="currentWeather">
    <div class="loading">Search for a city to see weather...</div>
  </div>

  <div class="forecast" id="forecast"></div>

  <div class="recent-searches" id="recentSearches">
    <h3>Recent Searches</h3>
    <div class="recent-list"></div>
  </div>
</div>
*/

// JavaScript
class WeatherApp {
  constructor() {
    this.apiKey = 'YOUR_API_KEY_HERE'; // Get from https://openweathermap.org/api
    this.baseUrl = 'https://api.openweathermap.org/data/2.5';
    this.isCelsius = true;
    this.recentSearches = JSON.parse(localStorage.getItem('recentSearches')) || [];

    this.initializeElements();
    this.setupEventListeners();
    this.updateRecentSearches();

    // Load default city
    this.getWeatherByCity('London');
  }

  initializeElements() {
    this.cityInput = document.getElementById('cityInput');
    this.searchBtn = document.getElementById('searchBtn');
    this.locationBtn = document.getElementById('locationBtn');
    this.unitToggle = document.getElementById('unitToggle');
    this.currentWeather = document.getElementById('currentWeather');
    this.forecast = document.getElementById('forecast');
    this.recentList = document.querySelector('.recent-list');
  }

  setupEventListeners() {
    this.searchBtn.addEventListener('click', () => this.searchCity());
    this.cityInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.searchCity();
    });

    this.locationBtn.addEventListener('click', () => this.getLocationWeather());
    this.unitToggle.addEventListener('click', () => this.toggleUnits());
  }

  searchCity() {
    const city = this.cityInput.value.trim();
    if (!city) return;

    this.getWeatherByCity(city);
    this.cityInput.value = '';
  }

  async getWeatherByCity(city) {
    try {
      this.showLoading();

      // Fetch current weather
      const currentResponse = await fetch(
        `${this.baseUrl}/weather?q=${city}&units=metric&appid=${this.apiKey}`
      );

      if (!currentResponse.ok) throw new Error('City not found');

      const currentData = await currentResponse.json();

      // Fetch forecast
      const forecastResponse = await fetch(
        `${this.baseUrl}/forecast?q=${city}&units=metric&appid=${this.apiKey}`
      );
      const forecastData = await forecastResponse.json();

      this.displayCurrentWeather(currentData);
      this.displayForecast(forecastData);
      this.addToRecentSearches(city);

    } catch (error) {
      this.showError(error.message);
    }
  }

  getLocationWeather() {
    if (!navigator.geolocation) {
      this.showError('Geolocation is not supported by your browser');
      return;
    }

    navigator.geolocation.getCurrentPosition(
      async (position) => {
        const { latitude, longitude } = position.coords;

        try {
          this.showLoading();

          const response = await fetch(
            `${this.baseUrl}/weather?lat=${latitude}&lon=${longitude}&units=metric&appid=${this.apiKey}`
          );

          const data = await response.json();
          this.getWeatherByCity(data.name);

        } catch (error) {
          this.showError('Failed to get location weather');
        }
      },
      () => {
        this.showError('Unable to retrieve your location');
      }
    );
  }

  displayCurrentWeather(data) {
    const temp = this.isCelsius ? 
      `${Math.round(data.main.temp)}°C` : 
      `${Math.round((data.main.temp * 9/5) + 32)}°F`;

    const html = `
      <div class="weather-card">
        <div class="city-name">${data.name}, ${data.sys.country}</div>
        <div class="weather-main">
          <img src="https://openweathermap.org/img/wn/${data.weather[0].icon}@2x.png" 
               alt="${data.weather[0].description}">
          <div class="temp">${temp}</div>
        </div>
        <div class="weather-desc">${data.weather[0].description}</div>
        <div class="weather-details">
          <div class="detail">
            <span>Humidity:</span>
            <span>${data.main.humidity}%</span>
          </div>
          <div class="detail">
            <span>Wind:</span>
            <span>${data.wind.speed} m/s</span>
          </div>
          <div class="detail">
            <span>Pressure:</span>
            <span>${data.main.pressure} hPa</span>
          </div>
        </div>
      </div>
    `;

    this.currentWeather.innerHTML = html;
  }

  displayForecast(data) {
    // Get daily forecast (every 8th item for 5 days)
    const dailyForecast = data.list.filter((_, index) => index % 8 === 0).slice(0, 5);

    let html = '<h2>5-Day Forecast</h2><div class="forecast-cards">';

    dailyForecast.forEach(day => {
      const date = new Date(day.dt * 1000);
      const dayName = date.toLocaleDateString('en-US', { weekday: 'short' });

      const temp = this.isCelsius ? 
        `${Math.round(day.main.temp)}°C` : 
        `${Math.round((day.main.temp * 9/5) + 32)}°F`;

      html += `
        <div class="forecast-card">
          <div class="day">${dayName}</div>
          <img src="https://openweathermap.org/img/wn/${day.weather[0].icon}.png" 
               alt="${day.weather[0].description}">
          <div class="forecast-temp">${temp}</div>
          <div class="forecast-desc">${day.weather[0].description}</div>
        </div>
      `;
    });

    html += '</div>';
    this.forecast.innerHTML = html;
  }

  toggleUnits() {
    this.isCelsius = !this.isCelsius;
    this.unitToggle.textContent = this.isCelsius ? '°C / °F' : '°F / °C';

    // Refresh current display with new units
    const currentCity = this.currentWeather.querySelector('.city-name');
    if (currentCity) {
      const city = currentCity.textContent.split(',')[0];
      this.getWeatherByCity(city);
    }
  }

  addToRecentSearches(city) {
    // Remove if already exists
    this.recentSearches = this.recentSearches.filter(c => c.toLowerCase() !== city.toLowerCase());

    // Add to beginning
    this.recentSearches.unshift(city);

    // Keep only last 5 searches
    if (this.recentSearches.length > 5) {
      this.recentSearches.pop();
    }

    // Save to localStorage
    localStorage.setItem('recentSearches', JSON.stringify(this.recentSearches));

    this.updateRecentSearches();
  }

  updateRecentSearches() {
    this.recentList.innerHTML = '';

    this.recentSearches.forEach(city => {
      const button = document.createElement('button');
      button.textContent = city;
      button.className = 'recent-city';
      button.addEventListener('click', () => this.getWeatherByCity(city));
      this.recentList.appendChild(button);
    });
  }

  showLoading() {
    this.currentWeather.innerHTML = '<div class="loading">Loading weather data...</div>';
    this.forecast.innerHTML = '';
  }

  showError(message) {
    this.currentWeather.innerHTML = 
      `<div class="error">Error: ${message}</div>`;
  }
}

