// Complete weather dashboard implementation
class WeatherDashboard {
  constructor() {
    this.API_KEY = 'your_api_key_here';
    this.BASE_URL = 'https://api.openweathermap.org/data/2.5';
    this.units = 'metric'; // 'metric' for Celsius, 'imperial' for Fahrenheit

    this.initializeElements();
    this.setupEventListeners();
    this.loadLastSearchedCity();
  }

  initializeElements() {
    this.searchInput = document.getElementById('searchInput');
    this.searchBtn = document.getElementById('searchBtn');
    this.unitToggle = document.getElementById('unitToggle');
    this.currentWeather = document.getElementById('currentWeather');
    this.forecast = document.getElementById('forecast');
    this.errorMessage = document.getElementById('errorMessage');
  }

  setupEventListeners() {
    this.searchBtn.addEventListener('click', () => this.searchWeather());
    this.searchInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.searchWeather();
    });
    this.unitToggle.addEventListener('change', () => this.toggleUnits());
  }

  async searchWeather() {
    const city = this.searchInput.value.trim();
    if (!city) return;

    try {
      this.showLoading(true);
      this.hideError();

      // Get coordinates first for more accurate results
      const coords = await this.getCityCoordinates(city);

      // Fetch current weather and forecast in parallel
      const [current, forecast] = await Promise.all([
        this.fetchCurrentWeather(coords.lat, coords.lon),
        this.fetchForecast(coords.lat, coords.lon)
      ]);

      this.displayCurrentWeather(current);
      this.displayForecast(forecast);
      this.saveLastSearchedCity(city);

    } catch (error) {
      this.showError('City not found or API error');
      console.error('Error fetching weather:', error);
    } finally {
      this.showLoading(false);
    }
  }

  async getCityCoordinates(city) {
    const url = `https://api.openweathermap.org/geo/1.0/direct?q=${city}&limit=1&appid=${this.API_KEY}`;
    const response = await fetch(url);

    if (!response.ok) throw new Error('Failed to fetch city');

    const data = await response.json();
    if (!data.length) throw new Error('City not found');

    return {
      lat: data[0].lat,
      lon: data[0].lon,
      name: data[0].name,
      country: data[0].country
    };
  }

  async fetchCurrentWeather(lat, lon) {
    const url = `${this.BASE_URL}/weather?lat=${lat}&lon=${lon}&units=${this.units}&appid=${this.API_KEY}`;
    const response = await fetch(url);

    if (!response.ok) throw new Error('Failed to fetch weather');

    return await response.json();
  }

  async fetchForecast(lat, lon) {
    const url = `${this.BASE_URL}/forecast?lat=${lat}&lon=${lon}&units=${this.units}&appid=${this.API_KEY}`;
    const response = await fetch(url);

    if (!response.ok) throw new Error('Failed to fetch forecast');

    const data = await response.json();
    return this.processForecastData(data.list);
  }

  processForecastData(forecastList) {
    // Group by day and get midday forecast for each day
    const groupedByDay = {};

    forecastList.forEach(item => {
      const date = new Date(item.dt * 1000);
      const day = date.toLocaleDateString();

      if (!groupedByDay[day]) {
        groupedByDay[day] = [];
      }
      groupedByDay[day].push(item);
    });

    // Get 5 days forecast (skip today)
    const days = Object.keys(groupedByDay).slice(1, 6);

    return days.map(day => {
      const dayForecasts = groupedByDay[day];
      const middayForecast = dayForecasts.find(f => {
        const hour = new Date(f.dt * 1000).getHours();
        return hour >= 11 && hour <= 14;
      }) || dayForecasts[Math.floor(dayForecasts.length / 2)];

      return {
        date: day,
        temp: middayForecast.main.temp,
        description: middayForecast.weather[0].description,
        icon: middayForecast.weather[0].icon,
        humidity: middayForecast.main.humidity,
        windSpeed: middayForecast.wind.speed
      };
    });
  }

  displayCurrentWeather(data) {
    const tempUnit = this.units === 'metric' ? '°C' : '°F';
    const windUnit = this.units === 'metric' ? 'm/s' : 'mph';

    this.currentWeather.innerHTML = `
      <div class="weather-header">
        <h2>${data.name}, ${data.sys.country}</h2>
        <p class="date">${new Date().toLocaleDateString()}</p>
      </div>

      <div class="weather-main">
        <div class="temperature">
          <span class="temp">${Math.round(data.main.temp)}${tempUnit}</span>
          <p class="description">${data.weather[0].description}</p>
        </div>

        <img src="https://openweathermap.org/img/wn/${data.weather[0].icon}@2x.png" 
             alt="${data.weather[0].description}">
      </div>

      <div class="weather-details">
        <div class="detail">
          <span class="label">Feels Like</span>
          <span class="value">${Math.round(data.main.feels_like)}${tempUnit}</span>
        </div>
        <div class="detail">
          <span class="label">Humidity</span>
          <span class="value">${data.main.humidity}%</span>
        </div>
        <div class="detail">
          <span class="label">Wind</span>
          <span class="value">${data.wind.speed} ${windUnit}</span>
        </div>
        <div class="detail">
          <span class="label">Pressure</span>
          <span class="value">${data.main.pressure} hPa</span>
        </div>
      </div>
    `;
  }

  displayForecast(forecastData) {
    const tempUnit = this.units === 'metric' ? '°C' : '°F';

    this.forecast.innerHTML = forecastData.map(day => `
      <div class="forecast-day">
        <h4>${new Date(day.date).toLocaleDateString('en-US', { weekday: 'short' })}</h4>
        <img src="https://openweathermap.org/img/wn/${day.icon}.png" alt="${day.description}">
        <div class="temp-range">${Math.round(day.temp)}${tempUnit}</div>
        <p class="description">${day.description}</p>
        <div class="details">
          <span>💧 ${day.humidity}%</span>
          <span>💨 ${day.windSpeed.toFixed(1)}</span>
        </div>
      </div>
    `).join('');
  }

  toggleUnits() {
    this.units = this.unitToggle.checked ? 'imperial' : 'metric';
    // Re-fetch weather with new units
    const currentCity = this.searchInput.value;
    if (currentCity) {
      this.searchInput.value = currentCity;
      this.searchWeather();
    }
  }

  showLoading(show) {
    const loading = document.getElementById('loading');
    loading.style.display = show ? 'block' : 'none';
  }

  showError(message) {
    this.errorMessage.textContent = message;
    this.errorMessage.style.display = 'block';
  }

  hideError() {
    this.errorMessage.style.display = 'none';
  }

  saveLastSearchedCity(city) {
    localStorage.setItem('lastSearchedCity', city);
  }

  loadLastSearchedCity() {
    const lastCity = localStorage.getItem('lastSearchedCity');
    if (lastCity) {
      this.searchInput.value = lastCity;
      this.searchWeather();
    }
  }
}

