// Complete Expense Tracker Implementation
class ExpenseTracker {
  constructor() {
    this.expenses = [];
    this.categories = ['Food', 'Transport', 'Shopping', 'Entertainment', 'Bills', 'Healthcare', 'Other'];
    this.monthlyBudget = 2000;

    this.initializeElements();
    this.loadFromLocalStorage();
    this.setupEventListeners();
    this.updateUI();
    this.initializeCharts();
  }

  initializeElements() {
    this.expenseForm = document.getElementById('expenseForm');
    this.expenseName = document.getElementById('expenseName');
    this.expenseAmount = document.getElementById('expenseAmount');
    this.expenseCategory = document.getElementById('expenseCategory');
    this.expenseDate = document.getElementById('expenseDate');
    this.expensesList = document.getElementById('expensesList');
    this.totalAmount = document.getElementById('totalAmount');
    this.budgetInput = document.getElementById('budgetInput');
    this.setBudgetBtn = document.getElementById('setBudgetBtn');
    this.budgetDisplay = document.getElementById('budgetDisplay');
    this.budgetProgress = document.getElementById('budgetProgress');
    this.categoryChart = document.getElementById('categoryChart').getContext('2d');
    this.monthlyChart = document.getElementById('monthlyChart').getContext('2d');
  }

  setupEventListeners() {
    this.expenseForm.addEventListener('submit', (e) => {
      e.preventDefault();
      this.addExpense();
    });

    this.setBudgetBtn.addEventListener('click', () => {
      this.setBudget();
    });

    this.budgetInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.setBudget();
    });

    // Initialize categories dropdown
    this.categories.forEach(category => {
      const option = document.createElement('option');
      option.value = category;
      option.textContent = category;
      this.expenseCategory.appendChild(option);
    });

    // Set default date to today
    this.expenseDate.valueAsDate = new Date();
  }

  addExpense() {
    const expense = {
      id: Date.now(),
      name: this.expenseName.value.trim(),
      amount: parseFloat(this.expenseAmount.value),
      category: this.expenseCategory.value,
      date: this.expenseDate.value,
      timestamp: new Date().toISOString()
    };

    if (!expense.name || isNaN(expense.amount) || expense.amount <= 0) {
      alert('Please enter valid expense details');
      return;
    }

    this.expenses.push(expense);
    this.saveToLocalStorage();
    this.updateUI();
    this.updateCharts();
    this.resetForm();
  }

  editExpense(id) {
    const expense = this.expenses.find(e => e.id === id);
    if (!expense) return;

    this.expenseName.value = expense.name;
    this.expenseAmount.value = expense.amount;
    this.expenseCategory.value = expense.category;
    this.expenseDate.value = expense.date;

    // Remove the expense from list
    this.expenses = this.expenses.filter(e => e.id !== id);
    this.saveToLocalStorage();
    this.updateUI();
  }

  deleteExpense(id) {
    if (confirm('Are you sure you want to delete this expense?')) {
      this.expenses = this.expenses.filter(expense => expense.id !== id);
      this.saveToLocalStorage();
      this.updateUI();
      this.updateCharts();
    }
  }

  setBudget() {
    const budget = parseFloat(this.budgetInput.value);
    if (!isNaN(budget) && budget > 0) {
      this.monthlyBudget = budget;
      localStorage.setItem('monthlyBudget', budget.toString());
      this.updateBudgetDisplay();
      this.budgetInput.value = '';
    }
  }

  updateUI() {
    // Sort expenses by date (newest first)
    this.expenses.sort((a, b) => new Date(b.date) - new Date(a.date));

    // Update expenses list
    this.expensesList.innerHTML = this.expenses.map(expense => {
      const date = new Date(expense.date).toLocaleDateString('en-US', {
        year: 'numeric',
        month: 'short',
        day: 'numeric'
      });

      return `
        <div class="expense-item" data-id="${expense.id}">
          <div class="expense-info">
            <div class="expense-name">${expense.name}</div>
            <div class="expense-category">${expense.category}</div>
            <div class="expense-date">${date}</div>
          </div>
          <div class="expense-actions">
            <span class="expense-amount">$${expense.amount.toFixed(2)}</span>
            <button class="btn-edit" onclick="expenseTracker.editExpense(${expense.id})">Edit</button>
            <button class="btn-delete" onclick="expenseTracker.deleteExpense(${expense.id})">Delete</button>
          </div>
        </div>
      `;
    }).join('');

    // Update total
    const total = this.expenses.reduce((sum, expense) => sum + expense.amount, 0);
    this.totalAmount.textContent = total.toFixed(2);

    this.updateBudgetDisplay();
  }

  updateBudgetDisplay() {
    const total = this.expenses.reduce((sum, expense) => sum + expense.amount, 0);
    const percentage = (total / this.monthlyBudget) * 100;

    this.budgetDisplay.innerHTML = `
      <div>Budget: <strong>$${this.monthlyBudget.toFixed(2)}</strong></div>
      <div>Spent: <strong>$${total.toFixed(2)}</strong></div>
      <div>Remaining: <strong>$${(this.monthlyBudget - total).toFixed(2)}</strong></div>
    `;

    this.budgetProgress.style.width = `${Math.min(percentage, 100)}%`;
    this.budgetProgress.className = `budget-progress ${percentage > 80 ? 'over-budget' : ''}`;
  }

  initializeCharts() {
    // Category Pie Chart
    this.categoryChartInstance = new Chart(this.categoryChart, {
      type: 'doughnut',
      data: {
        labels: this.categories,
        datasets: [{
          data: this.categories.map(() => 0),
          backgroundColor: [
            '#FF6384', '#36A2EB', '#FFCE56', '#4BC0C0',
            '#9966FF', '#FF9F40', '#C9CBCF'
          ]
        }]
      },
      options: {
        responsive: true,
        plugins: {
          legend: { position: 'bottom' },
          title: { display: true, text: 'Expenses by Category' }
        }
      }
    });

    // Monthly Line Chart
    this.monthlyChartInstance = new Chart(this.monthlyChart, {
      type: 'line',
      data: {
        labels: this.getLast12Months(),
        datasets: [{
          label: 'Monthly Expenses',
          data: Array(12).fill(0),
          borderColor: '#36A2EB',
          backgroundColor: 'rgba(54, 162, 235, 0.2)',
          tension: 0.4
        }]
      },
      options: {
        responsive: true,
        plugins: {
          title: { display: true, text: 'Monthly Spending Trend' }
        },
        scales: {
          y: { beginAtZero: true }
        }
      }
    });
  }

  updateCharts() {
    // Update category chart
    const categoryTotals = this.categories.map(category => 
      this.expenses
        .filter(expense => expense.category === category)
        .reduce((sum, expense) => sum + expense.amount, 0)
    );

    this.categoryChartInstance.data.datasets[0].data = categoryTotals;
    this.categoryChartInstance.update();

    // Update monthly chart
    const monthlyData = this.getMonthlyExpenseData();
    this.monthlyChartInstance.data.datasets[0].data = monthlyData;
    this.monthlyChartInstance.update();
  }

  getMonthlyExpenseData() {
    const monthlyTotals = Array(12).fill(0);
    const currentYear = new Date().getFullYear();

    this.expenses.forEach(expense => {
      const date = new Date(expense.date);
      if (date.getFullYear() === currentYear) {
        const month = date.getMonth();
        monthlyTotals[month] += expense.amount;
      }
    });

    return monthlyTotals;
  }

  getLast12Months() {
    const months = [];
    const date = new Date();

    for (let i = 11; i >= 0; i--) {
      const d = new Date(date.getFullYear(), date.getMonth() - i, 1);
      months.push(d.toLocaleDateString('en-US', { month: 'short' }));
    }

    return months;
  }

  resetForm() {
    this.expenseForm.reset();
    this.expenseDate.valueAsDate = new Date();
    this.expenseName.focus();
  }

  saveToLocalStorage() {
    localStorage.setItem('expenses', JSON.stringify(this.expenses));
  }

  loadFromLocalStorage() {
    const savedExpenses = localStorage.getItem('expenses');
    const savedBudget = localStorage.getItem('monthlyBudget');

    if (savedExpenses) {
      this.expenses = JSON.parse(savedExpenses);
    }

    if (savedBudget) {
      this.monthlyBudget = parseFloat(savedBudget);
    }
  }
}

