// Client-side Real-time Chat Application
class ChatApplication {
  constructor() {
    this.socket = null;
    this.currentUser = null;
    this.currentRoom = 'general';
    this.onlineUsers = [];

    this.initializeElements();
    this.setupEventListeners();
    this.connectToServer();
  }

  initializeElements() {
    this.loginModal = document.getElementById('loginModal');
    this.chatContainer = document.getElementById('chatContainer');
    this.usernameInput = document.getElementById('usernameInput');
    this.loginBtn = document.getElementById('loginBtn');
    this.messageInput = document.getElementById('messageInput');
    this.sendBtn = document.getElementById('sendBtn');
    this.messagesContainer = document.getElementById('messagesContainer');
    this.onlineUsersList = document.getElementById('onlineUsersList');
    this.roomSelect = document.getElementById('roomSelect');
    this.typingIndicator = document.getElementById('typingIndicator');
    this.roomsList = document.getElementById('roomsList');
    this.createRoomBtn = document.getElementById('createRoomBtn');
    this.newRoomName = document.getElementById('newRoomName');
  }

  setupEventListeners() {
    // Login
    this.loginBtn.addEventListener('click', () => this.login());
    this.usernameInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.login();
    });

    // Messaging
    this.sendBtn.addEventListener('click', () => this.sendMessage());
    this.messageInput.addEventListener('keypress', (e) => {
      if (e.key === 'Enter') this.sendMessage();
    });

    // Typing indicator
    this.messageInput.addEventListener('input', () => {
      this.socket.emit('typing', this.currentRoom);
    });

    // Room management
    this.roomSelect.addEventListener('change', (e) => {
      this.changeRoom(e.target.value);
    });

    this.createRoomBtn.addEventListener('click', () => {
      this.createRoom();
    });
  }

  connectToServer() {
    // Connect to WebSocket server
    this.socket = io('http://localhost:3000');

    // Socket event listeners
    this.socket.on('connect', () => {
      console.log('Connected to server');
    });

    this.socket.on('message', (data) => {
      this.displayMessage(data);
    });

    this.socket.on('userJoined', (data) => {
      this.showNotification(`${data.username} joined the chat`);
      this.updateOnlineUsers(data.users);
    });

    this.socket.on('userLeft', (data) => {
      this.showNotification(`${data.username} left the chat`);
      this.updateOnlineUsers(data.users);
    });

    this.socket.on('typing', (data) => {
      this.showTypingIndicator(data.username);
    });

    this.socket.on('stopTyping', () => {
      this.hideTypingIndicator();
    });

    this.socket.on('roomList', (rooms) => {
      this.updateRoomsList(rooms);
    });

    this.socket.on('roomCreated', (room) => {
      this.addRoomToSelect(room);
    });

    this.socket.on('previousMessages', (messages) => {
      messages.forEach(msg => this.displayMessage(msg));
    });

    this.socket.on('error', (error) => {
      this.showError(error);
    });
  }

  login() {
    const username = this.usernameInput.value.trim();
    if (!username) {
      alert('Please enter a username');
      return;
    }

    this.currentUser = username;
    this.socket.emit('join', {
      username: username,
      room: this.currentRoom
    });

    // Show chat interface
    this.loginModal.style.display = 'none';
    this.chatContainer.style.display = 'block';

    // Focus message input
    this.messageInput.focus();
  }

  sendMessage() {
    const message = this.messageInput.value.trim();
    if (!message) return;

    const messageData = {
      username: this.currentUser,
      room: this.currentRoom,
      message: message,
      timestamp: new Date().toISOString()
    };

    this.socket.emit('sendMessage', messageData);
    this.messageInput.value = '';
    this.socket.emit('stopTyping', this.currentRoom);
  }

  changeRoom(roomName) {
    if (roomName === this.currentRoom) return;

    // Leave current room
    this.socket.emit('leaveRoom', this.currentRoom);

    // Clear messages
    this.messagesContainer.innerHTML = '';

    // Join new room
    this.currentRoom = roomName;
    this.socket.emit('joinRoom', {
      username: this.currentUser,
      room: roomName
    });

    this.showNotification(`Joined room: ${roomName}`);
  }

  createRoom() {
    const roomName = this.newRoomName.value.trim();
    if (!roomName) {
      alert('Please enter a room name');
      return;
    }

    this.socket.emit('createRoom', roomName);
    this.newRoomName.value = '';
  }

  displayMessage(data) {
    const messageElement = document.createElement('div');
    messageElement.className = 'message';

    const time = new Date(data.timestamp).toLocaleTimeString([], {
      hour: '2-digit',
      minute: '2-digit'
    });

    const isCurrentUser = data.username === this.currentUser;

    messageElement.innerHTML = `
      <div class="message-header ${isCurrentUser ? 'current-user' : ''}">
        <span class="message-username">${data.username}</span>
        <span class="message-time">${time}</span>
      </div>
      <div class="message-content">${this.escapeHtml(data.message)}</div>
    `;

    this.messagesContainer.appendChild(messageElement);
    this.messagesContainer.scrollTop = this.messagesContainer.scrollHeight;
  }

  showNotification(message) {
    const notification = document.createElement('div');
    notification.className = 'notification';
    notification.textContent = message;

    this.messagesContainer.appendChild(notification);
    this.messagesContainer.scrollTop = this.messagesContainer.scrollHeight;

    // Auto-remove notification after 3 seconds
    setTimeout(() => {
      notification.remove();
    }, 3000);
  }

  updateOnlineUsers(users) {
    this.onlineUsers = users;
    this.onlineUsersList.innerHTML = users
      .map(user => `<div class="user-item">${user}</div>`)
      .join('');
  }

  showTypingIndicator(username) {
    this.typingIndicator.textContent = `${username} is typing...`;
    this.typingIndicator.style.display = 'block';

    // Auto-hide after 2 seconds
    clearTimeout(this.typingTimeout);
    this.typingTimeout = setTimeout(() => {
      this.hideTypingIndicator();
    }, 2000);
  }

  hideTypingIndicator() {
    this.typingIndicator.style.display = 'none';
  }

  updateRoomsList(rooms) {
    this.roomsList.innerHTML = '';
    rooms.forEach(room => {
      this.addRoomToSelect(room);
    });
  }

  addRoomToSelect(room) {
    const option = document.createElement('option');
    option.value = room;
    option.textContent = room;
    this.roomSelect.appendChild(option);

    // Also add to rooms list display
    const roomItem = document.createElement('div');
    roomItem.className = 'room-item';
    roomItem.textContent = room;
    roomItem.onclick = () => this.changeRoom(room);
    this.roomsList.appendChild(roomItem);
  }

  showError(error) {
    const errorDiv = document.createElement('div');
    errorDiv.className = 'error-message';
    errorDiv.textContent = error;

    document.body.appendChild(errorDiv);

    setTimeout(() => {
      errorDiv.remove();
    }, 5000);
  }

  escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

