class TaskManager {
  constructor() {
    this.tasks = [];
    this.columns = ['todo', 'inProgress', 'review', 'done'];
    this.columnNames = {
      todo: 'To Do',
      inProgress: 'In Progress',
      review: 'Review',
      done: 'Done'
    };
    this.teams = ['Frontend', 'Backend', 'Design', 'Marketing', 'QA'];
    this.priorities = ['Low', 'Medium', 'High', 'Critical'];

    this.initializeElements();
    this.setupEventListeners();
    this.loadFromLocalStorage();
    this.renderBoard();
    this.initializeDragAndDrop();
  }

  initializeElements() {
    this.taskModal = document.getElementById('taskModal');
    this.taskForm = document.getElementById('taskForm');
    this.taskTitle = document.getElementById('taskTitle');
    this.taskDescription = document.getElementById('taskDescription');
    this.taskPriority = document.getElementById('taskPriority');
    this.taskDeadline = document.getElementById('taskDeadline');
    this.taskTeam = document.getElementById('taskTeam');
    this.taskAssignee = document.getElementById('taskAssignee');
    this.addTaskBtn = document.getElementById('addTaskBtn');
    this.closeModalBtn = document.getElementById('closeModalBtn');
    this.searchInput = document.getElementById('searchInput');
    this.filterPriority = document.getElementById('filterPriority');
    this.filterTeam = document.getElementById('filterTeam');
    this.clearFiltersBtn = document.getElementById('clearFiltersBtn');
    this.columnsContainer = document.querySelector('.columns-container');

    // Initialize dropdowns
    this.priorities.forEach(priority => {
      const option = document.createElement('option');
      option.value = priority;
      option.textContent = priority;
      this.taskPriority.appendChild(option);
    });

    this.teams.forEach(team => {
      const option = document.createElement('option');
      option.value = team;
      option.textContent = team;
      this.taskTeam.appendChild(option);
    });

    // Initialize filter dropdowns
    this.filterPriority.innerHTML = `
      <option value="all">All Priorities</option>
      ${this.priorities.map(p => `<option value="${p}">${p}</option>`).join('')}
    `;

    this.filterTeam.innerHTML = `
      <option value="all">All Teams</option>
      ${this.teams.map(t => `<option value="${t}">${t}</option>`).join('')}
    `;

    // Set default deadline to tomorrow
    const tomorrow = new Date();
    tomorrow.setDate(tomorrow.getDate() + 1);
    this.taskDeadline.valueAsDate = tomorrow;
  }

  setupEventListeners() {
    // Task modal
    this.addTaskBtn.addEventListener('click', () => {
      this.openTaskModal();
    });

    this.closeModalBtn.addEventListener('click', () => {
      this.closeTaskModal();
    });

    this.taskForm.addEventListener('submit', (e) => {
      e.preventDefault();
      this.saveTask();
    });

    // Filters
    this.searchInput.addEventListener('input', () => {
      this.applyFilters();
    });

    this.filterPriority.addEventListener('change', () => {
      this.applyFilters();
    });

    this.filterTeam.addEventListener('change', () => {
      this.applyFilters();
    });

    this.clearFiltersBtn.addEventListener('click', () => {
      this.clearFilters();
    });

    // Close modal on outside click
    window.addEventListener('click', (e) => {
      if (e.target === this.taskModal) {
        this.closeTaskModal();
      }
    });
  }

  initializeDragAndDrop() {
    // Make all tasks draggable
    document.addEventListener('dragstart', (e) => {
      if (e.target.classList.contains('task-card')) {
        e.dataTransfer.setData('text/plain', e.target.dataset.taskId);
        e.target.classList.add('dragging');
      }
    });

    document.addEventListener('dragend', (e) => {
      if (e.target.classList.contains('task-card')) {
        e.target.classList.remove('dragging');
      }
    });

    // Make columns droppable
    this.columns.forEach(columnId => {
      const column = document.getElementById(columnId);

      column.addEventListener('dragover', (e) => {
        e.preventDefault();
        column.classList.add('drag-over');
      });

      column.addEventListener('dragleave', () => {
        column.classList.remove('drag-over');
      });

      column.addEventListener('drop', (e) => {
        e.preventDefault();
        column.classList.remove('drag-over');

        const taskId = e.dataTransfer.getData('text/plain');
        const task = this.tasks.find(t => t.id === taskId);

        if (task && task.status !== columnId) {
          task.status = columnId;
          this.saveToLocalStorage();
          this.renderBoard();
        }
      });
    });
  }

  openTaskModal(task = null) {
    this.editingTask = task;

    if (task) {
      // Edit mode
      this.taskTitle.value = task.title;
      this.taskDescription.value = task.description;
      this.taskPriority.value = task.priority;
      this.taskDeadline.value = task.deadline;
      this.taskTeam.value = task.team;
      this.taskAssignee.value = task.assignee || '';
      document.getElementById('modalTitle').textContent = 'Edit Task';
    } else {
      // Add mode
      this.taskForm.reset();
      const tomorrow = new Date();
      tomorrow.setDate(tomorrow.getDate() + 1);
      this.taskDeadline.valueAsDate = tomorrow;
      document.getElementById('modalTitle').textContent = 'Add New Task';
    }

    this.taskModal.style.display = 'block';
    this.taskTitle.focus();
  }

  closeTaskModal() {
    this.taskModal.style.display = 'none';
    this.taskForm.reset();
    this.editingTask = null;
  }

  saveTask() {
    const taskData = {
      id: this.editingTask ? this.editingTask.id : Date.now().toString(),
      title: this.taskTitle.value.trim(),
      description: this.taskDescription.value.trim(),
      priority: this.taskPriority.value,
      deadline: this.taskDeadline.value,
      team: this.taskTeam.value,
      assignee: this.taskAssignee.value.trim(),
      status: this.editingTask ? this.editingTask.status : 'todo',
      createdAt: this.editingTask ? this.editingTask.createdAt : new Date().toISOString(),
      updatedAt: new Date().toISOString()
    };

    if (!taskData.title) {
      alert('Please enter a task title');
      return;
    }

    if (this.editingTask) {
      // Update existing task
      const index = this.tasks.findIndex(t => t.id === this.editingTask.id);
      this.tasks[index] = taskData;
    } else {
      // Add new task
      this.tasks.push(taskData);
    }

    this.saveToLocalStorage();
    this.renderBoard();
    this.closeTaskModal();
  }

  deleteTask(taskId) {
    if (confirm('Are you sure you want to delete this task?')) {
      this.tasks = this.tasks.filter(task => task.id !== taskId);
      this.saveToLocalStorage();
      this.renderBoard();
    }
  }

  renderBoard() {
    // Clear all columns
    this.columns.forEach(columnId => {
      const column = document.getElementById(columnId);
      column.innerHTML = `<h3>${this.columnNames[columnId]}</h3>`;
    });

    // Filter tasks based on search and filters
    const filteredTasks = this.filterTasks();

    // Render tasks in their respective columns
    filteredTasks.forEach(task => {
      const column = document.getElementById(task.status);
      if (column) {
        column.appendChild(this.createTaskCard(task));
      }
    });

    // Update task counts
    this.updateTaskCounts();
  }

  createTaskCard(task) {
    const card = document.createElement('div');
    card.className = 'task-card';
    card.dataset.taskId = task.id;
    card.draggable = true;

    const priorityClass = task.priority.toLowerCase().replace(' ', '-');
    const daysLeft = this.getDaysLeft(task.deadline);
    const deadlineClass = daysLeft < 0 ? 'overdue' : daysLeft <= 2 ? 'urgent' : '';

    card.innerHTML = `
      <div class="task-header">
        <span class="task-priority ${priorityClass}">${task.priority}</span>
        <div class="task-actions">
          <button class="btn-edit" onclick="taskManager.openTaskModal(${JSON.stringify(task).replace(/["']/g, '&quot;')})">Edit</button>
          <button class="btn-delete" onclick="taskManager.deleteTask('${task.id}')">Delete</button>
        </div>
      </div>
      <h4 class="task-title">${this.escapeHtml(task.title)}</h4>
      <p class="task-description">${this.escapeHtml(task.description)}</p>
      <div class="task-footer">
        <div class="task-meta">
          <span class="task-team">${task.team}</span>
          ${task.assignee ? `<span class="task-assignee">👤 ${task.assignee}</span>` : ''}
        </div>
        <div class="task-deadline ${deadlineClass}">
          ⏰ ${new Date(task.deadline).toLocaleDateString()}
          ${daysLeft < 0 ? ' (Overdue)' : daysLeft <= 2 ? ' (Soon)' : ''}
        </div>
      </div>
    `;

    return card;
  }

  filterTasks() {
    const searchTerm = this.searchInput.value.toLowerCase();
    const priorityFilter = this.filterPriority.value;
    const teamFilter = this.filterTeam.value;

    return this.tasks.filter(task => {
      // Search filter
      const matchesSearch = !searchTerm || 
        task.title.toLowerCase().includes(searchTerm) ||
        task.description.toLowerCase().includes(searchTerm) ||
        task.assignee.toLowerCase().includes(searchTerm);

      // Priority filter
      const matchesPriority = priorityFilter === 'all' || task.priority === priorityFilter;

      // Team filter
      const matchesTeam = teamFilter === 'all' || task.team === teamFilter;

      return matchesSearch && matchesPriority && matchesTeam;
    });
  }

  applyFilters() {
    this.renderBoard();
  }

  clearFilters() {
    this.searchInput.value = '';
    this.filterPriority.value = 'all';
    this.filterTeam.value = 'all';
    this.renderBoard();
  }

  updateTaskCounts() {
    this.columns.forEach(columnId => {
      const column = document.getElementById(columnId);
      const count = this.tasks.filter(task => task.status === columnId).length;
      const header = column.querySelector('h3');
      header.textContent = `${this.columnNames[columnId]} (${count})`;
    });

    // Update total tasks
    document.getElementById('totalTasks').textContent = this.tasks.length;
  }

  getDaysLeft(deadline) {
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    const deadlineDate = new Date(deadline);
    deadlineDate.setHours(0, 0, 0, 0);

    const diffTime = deadlineDate - today;
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24));
  }

  saveToLocalStorage() {
    localStorage.setItem('tasks', JSON.stringify(this.tasks));
  }

  loadFromLocalStorage() {
    const savedTasks = localStorage.getItem('tasks');
    if (savedTasks) {
      this.tasks = JSON.parse(savedTasks);
    }
  }

  escapeHtml(text) {
    const div = document.createElement('div');
    div.textContent = text;
    return div.innerHTML;
  }
}

