// Complete E-commerce Product Dashboard
class ProductDashboard {
  constructor() {
    this.products = [];
    this.filteredProducts = [];
    this.cart = [];
    this.currentPage = 1;
    this.productsPerPage = 9;
    this.sortOption = 'default';
    this.currentFilters = {
      category: 'all',
      priceRange: [0, 1000],
      rating: 0
    };

    this.initializeElements();
    this.setupEventListeners();
    this.loadCartFromStorage();
    this.fetchProducts();
  }

  initializeElements() {
    // Product grid
    this.productsGrid = document.getElementById('productsGrid');
    this.loadingIndicator = document.getElementById('loadingIndicator');

    // Filter elements
    this.searchInput = document.getElementById('searchInput');
    this.categoryFilter = document.getElementById('categoryFilter');
    this.priceRangeMin = document.getElementById('priceRangeMin');
    this.priceRangeMax = document.getElementById('priceRangeMax');
    this.priceDisplay = document.getElementById('priceDisplay');
    this.ratingFilter = document.getElementById('ratingFilter');
    this.ratingDisplay = document.getElementById('ratingDisplay');
    this.sortSelect = document.getElementById('sortSelect');
    this.clearFiltersBtn = document.getElementById('clearFiltersBtn');

    // Cart elements
    this.cartIcon = document.getElementById('cartIcon');
    this.cartCount = document.getElementById('cartCount');
    this.cartModal = document.getElementById('cartModal');
    this.cartItems = document.getElementById('cartItems');
    this.cartTotal = document.getElementById('cartTotal');
    this.closeCartBtn = document.getElementById('closeCartBtn');
    this.checkoutBtn = document.getElementById('checkoutBtn');
    this.clearCartBtn = document.getElementById('clearCartBtn');

    // Pagination
    this.prevPageBtn = document.getElementById('prevPageBtn');
    this.nextPageBtn = document.getElementById('nextPageBtn');
    this.pageInfo = document.getElementById('pageInfo');

    // Initialize price range slider
    this.initializePriceRange();
  }

  setupEventListeners() {
    // Search
    this.searchInput.addEventListener('input', () => {
      this.applyFilters();
    });

    // Category filter
    this.categoryFilter.addEventListener('change', () => {
      this.currentFilters.category = this.categoryFilter.value;
      this.applyFilters();
    });

    // Price range
    this.priceRangeMin.addEventListener('input', () => {
      this.updatePriceDisplay();
      this.applyFilters();
    });

    this.priceRangeMax.addEventListener('input', () => {
      this.updatePriceDisplay();
      this.applyFilters();
    });

    // Rating filter
    this.ratingFilter.addEventListener('input', () => {
      this.ratingDisplay.textContent = `${this.ratingFilter.value}+`;
      this.currentFilters.rating = parseInt(this.ratingFilter.value);
      this.applyFilters();
    });

    // Sorting
    this.sortSelect.addEventListener('change', () => {
      this.sortOption = this.sortSelect.value;
      this.applyFilters();
    });

    // Clear filters
    this.clearFiltersBtn.addEventListener('click', () => {
      this.clearFilters();
    });

    // Cart
    this.cartIcon.addEventListener('click', () => {
      this.toggleCartModal();
    });

    this.closeCartBtn.addEventListener('click', () => {
      this.closeCartModal();
    });

    this.checkoutBtn.addEventListener('click', () => {
      this.checkout();
    });

    this.clearCartBtn.addEventListener('click', () => {
      this.clearCart();
    });

    // Pagination
    this.prevPageBtn.addEventListener('click', () => {
      this.prevPage();
    });

    this.nextPageBtn.addEventListener('click', () => {
      this.nextPage();
    });

    // Close modal on outside click
    window.addEventListener('click', (e) => {
      if (e.target === this.cartModal) {
        this.closeCartModal();
      }
    });
  }

  initializePriceRange() {
    // Set initial values
    this.priceRangeMin.value = 0;
    this.priceRangeMax.value = 1000;
    this.updatePriceDisplay();
  }

  updatePriceDisplay() {
    const min = parseInt(this.priceRangeMin.value);
    const max = parseInt(this.priceRangeMax.value);
    this.priceDisplay.textContent = `$${min} - $${max}`;
    this.currentFilters.priceRange = [min, max];
  }

  async fetchProducts() {
    try {
      this.showLoading(true);

      // Using Fake Store API or similar
      const response = await fetch('https://fakestoreapi.com/products');
      if (!response.ok) throw new Error('Failed to fetch products');

      this.products = await response.json();

      // Add mock categories if not present
      this.products.forEach((product, index) => {
        product.category = product.category || this.getMockCategory(index);
        product.rating = product.rating || {
          rate: Math.random() * 2 + 3, // Random rating between 3-5
          count: Math.floor(Math.random() * 1000)
        };
      });

      // Initialize categories dropdown
      this.initializeCategories();

      this.applyFilters();

    } catch (error) {
      console.error('Error fetching products:', error);
      this.showError('Failed to load products');
    } finally {
      this.showLoading(false);
    }
  }

  getMockCategory(index) {
    const categories = ['electronics', 'clothing', 'home', 'books', 'toys'];
    return categories[index % categories.length];
  }

  initializeCategories() {
    const categories = ['all', ...new Set(this.products.map(p => p.category))];

    this.categoryFilter.innerHTML = categories.map(category => {
      const displayName = category.charAt(0).toUpperCase() + category.slice(1);
      return `<option value="${category}">${displayName}</option>`;
    }).join('');
  }

  applyFilters() {
    const searchTerm = this.searchInput.value.toLowerCase();

    this.filteredProducts = this.products.filter(product => {
      // Search filter
      const matchesSearch = !searchTerm || 
        product.title.toLowerCase().includes(searchTerm) ||
        product.description.toLowerCase().includes(searchTerm);

      // Category filter
      const matchesCategory = this.currentFilters.category === 'all' || 
        product.category === this.currentFilters.category;

      // Price filter
      const [minPrice, maxPrice] = this.currentFilters.priceRange;
      const matchesPrice = product.price >= minPrice && product.price <= maxPrice;

      // Rating filter
      const matchesRating = product.rating.rate >= this.currentFilters.rating;

      return matchesSearch && matchesCategory && matchesPrice && matchesRating;
    });

    // Apply sorting
    this.sortProducts();

    // Reset to first page
    this.currentPage = 1;

    // Render products
    this.renderProducts();
    this.updatePagination();
  }

  sortProducts() {
    switch (this.sortOption) {
      case 'price-low':
        this.filteredProducts.sort((a, b) => a.price - b.price);
        break;
      case 'price-high':
        this.filteredProducts.sort((a, b) => b.price - a.price);
        break;
      case 'rating':
        this.filteredProducts.sort((a, b) => b.rating.rate - a.rating.rate);
        break;
      case 'name':
        this.filteredProducts.sort((a, b) => a.title.localeCompare(b.title));
        break;
      default:
        // Default sorting (by ID)
        this.filteredProducts.sort((a, b) => a.id - b.id);
    }
  }

  renderProducts() {
    const startIndex = (this.currentPage - 1) * this.productsPerPage;
    const endIndex = startIndex + this.productsPerPage;
    const productsToShow = this.filteredProducts.slice(startIndex, endIndex);

    this.productsGrid.innerHTML = productsToShow.map(product => {
      const stars = this.generateStarRating(product.rating.rate);
      const inCart = this.cart.some(item => item.id === product.id);

      return `
        <div class="product-card">
          <div class="product-image">
            <img src="${product.image}" alt="${product.title}">
            ${product.price < 50 ? '<span class="sale-badge">SALE</span>' : ''}
          </div>
          <div class="product-info">
            <h3 class="product-title">${this.truncateText(product.title, 50)}</h3>
            <div class="product-category">${product.category}</div>
            <div class="product-rating">
              ${stars}
              <span>(${product.rating.count})</span>
            </div>
            <p class="product-description">${this.truncateText(product.description, 100)}</p>
            <div class="product-footer">
              <div class="product-price">$${product.price.toFixed(2)}</div>
              <button class="btn-add-to-cart ${inCart ? 'in-cart' : ''}" 
                      onclick="productDashboard.toggleCart(${JSON.stringify(product).replace(/["']/g, '&quot;')})">
                ${inCart ? 'Remove from Cart' : 'Add to Cart'}
              </button>
            </div>
          </div>
        </div>
      `;
    }).join('');
  }

  generateStarRating(rating) {
    const fullStars = Math.floor(rating);
    const halfStar = rating % 1 >= 0.5;
    const emptyStars = 5 - fullStars - (halfStar ? 1 : 0);

    let stars = '';
    for (let i = 0; i < fullStars; i++) stars += '★';
    if (halfStar) stars += '½';
    for (let i = 0; i < emptyStars; i++) stars += '☆';

    return stars;
  }

  toggleCart(product) {
    const existingIndex = this.cart.findIndex(item => item.id === product.id);

    if (existingIndex >= 0) {
      // Remove from cart
      this.cart.splice(existingIndex, 1);
    } else {
      // Add to cart
      this.cart.push({
        ...product,
        quantity: 1,
        cartId: Date.now() + Math.random()
      });
    }

    this.saveCartToStorage();
    this.updateCartUI();
    this.renderProducts(); // Re-render to update button text
  }

  updateCartUI() {
    // Update cart count
    this.cartCount.textContent = this.cart.length;
    this.cartCount.style.display = this.cart.length > 0 ? 'block' : 'none';

    // Update cart modal
    this.renderCartItems();
  }

  renderCartItems() {
    if (this.cart.length === 0) {
      this.cartItems.innerHTML = '<p class="empty-cart">Your cart is empty</p>';
      this.cartTotal.textContent = '$0.00';
      return;
    }

    const cartHTML = this.cart.map(item => {
      const subtotal = item.price * item.quantity;

      return `
        <div class="cart-item">
          <img src="${item.image}" alt="${item.title}">
          <div class="cart-item-info">
            <h4>${this.truncateText(item.title, 30)}</h4>
            <div class="cart-item-price">$${item.price.toFixed(2)}</div>
          </div>
          <div class="cart-item-quantity">
            <button onclick="productDashboard.updateQuantity('${item.cartId}', -1)">-</button>
            <span>${item.quantity}</span>
            <button onclick="productDashboard.updateQuantity('${item.cartId}', 1)">+</button>
          </div>
          <div class="cart-item-subtotal">$${subtotal.toFixed(2)}</div>
          <button class="cart-item-remove" onclick="productDashboard.removeFromCart('${item.cartId}')">×</button>
        </div>
      `;
    }).join('');

    this.cartItems.innerHTML = cartHTML;

    // Update total
    const total = this.cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    this.cartTotal.textContent = `$${total.toFixed(2)}`;
  }

  updateQuantity(cartId, change) {
    const itemIndex = this.cart.findIndex(item => item.cartId === cartId);
    if (itemIndex >= 0) {
      this.cart[itemIndex].quantity += change;

      if (this.cart[itemIndex].quantity <= 0) {
        this.cart.splice(itemIndex, 1);
      }

      this.saveCartToStorage();
      this.updateCartUI();
    }
  }

  removeFromCart(cartId) {
    this.cart = this.cart.filter(item => item.cartId !== cartId);
    this.saveCartToStorage();
    this.updateCartUI();
    this.renderProducts();
  }

  clearCart() {
    if (confirm('Are you sure you want to clear your cart?')) {
      this.cart = [];
      this.saveCartToStorage();
      this.updateCartUI();
      this.renderProducts();
    }
  }

  checkout() {
    if (this.cart.length === 0) {
      alert('Your cart is empty');
      return;
    }

    const total = this.cart.reduce((sum, item) => sum + (item.price * item.quantity), 0);
    alert(`Order placed successfully! Total: $${total.toFixed(2)}\nThank you for your purchase.`);

    this.cart = [];
    this.saveCartToStorage();
    this.updateCartUI();
    this.renderProducts();
    this.closeCartModal();
  }

  toggleCartModal() {
    this.cartModal.style.display = 'block';
  }

  closeCartModal() {
    this.cartModal.style.display = 'none';
  }

  clearFilters() {
    this.searchInput.value = '';
    this.categoryFilter.value = 'all';
    this.priceRangeMin.value = 0;
    this.priceRangeMax.value = 1000;
    this.ratingFilter.value = 0;
    this.sortSelect.value = 'default';

    this.currentFilters = {
      category: 'all',
      priceRange: [0, 1000],
      rating: 0
    };

    this.updatePriceDisplay();
    this.ratingDisplay.textContent = '0+';
    this.applyFilters();
  }

  prevPage() {
    if (this.currentPage > 1) {
      this.currentPage--;
      this.renderProducts();
      this.updatePagination();
    }
  }

  nextPage() {
    const totalPages = Math.ceil(this.filteredProducts.length / this.productsPerPage);
    if (this.currentPage < totalPages) {
      this.currentPage++;
      this.renderProducts();
      this.updatePagination();
    }
  }

  updatePagination() {
    const totalPages = Math.ceil(this.filteredProducts.length / this.productsPerPage);
    const startIndex = (this.currentPage - 1) * this.productsPerPage + 1;
    const endIndex = Math.min(this.currentPage * this.productsPerPage, this.filteredProducts.length);

    this.pageInfo.textContent = `Showing ${startIndex}-${endIndex} of ${this.filteredProducts.length} products`;

    this.prevPageBtn.disabled = this.currentPage === 1;
    this.nextPageBtn.disabled = this.currentPage === totalPages;
  }

  showLoading(show) {
    this.loadingIndicator.style.display = show ? 'block' : 'none';
  }

  showError(message) {
    this.productsGrid.innerHTML = `
      <div class="error-message">
        <p>${message}</p>
        <button onclick="productDashboard.fetchProducts()">Retry</button>
      </div>
    `;
  }

  truncateText(text, maxLength) {
    if (text.length <= maxLength) return text;
    return text.substring(0, maxLength) + '...';
  }

  saveCartToStorage() {
    localStorage.setItem('cart', JSON.stringify(this.cart));
  }

  loadCartFromStorage() {
    const savedCart = localStorage.getItem('cart');
    if (savedCart) {
      this.cart = JSON.parse(savedCart);
      this.updateCartUI();
    }
  }
}

