// Backend: server.js
const express = require('express');
const http = require('http');
const socketIo = require('socket.io');
const mongoose = require('mongoose');
const cors = require('cors');

const app = express();
const server = http.createServer(app);
const io = socketIo(server, {
  cors: {
    origin: "http://localhost:3000",
    methods: ["GET", "POST"]
  }
});

app.use(cors());
app.use(express.json());

// MongoDB schemas
const messageSchema = new mongoose.Schema({
  room: String,
  username: String,
  message: String,
  timestamp: { type: Date, default: Date.now }
});

const userSchema = new mongoose.Schema({
  username: String,
  socketId: String,
  room: String,
  isOnline: { type: Boolean, default: true },
  lastSeen: { type: Date, default: Date.now }
});

const Message = mongoose.model('Message', messageSchema);
const User = mongoose.model('User', userSchema);

// Socket.io connection
io.on('connection', (socket) => {
  console.log('New client connected:', socket.id);

  // User joins a room
  socket.on('joinRoom', async ({ username, room }) => {
    try {
      socket.join(room);

      // Save user
      const user = new User({
        username,
        socketId: socket.id,
        room,
        isOnline: true
      });
      await user.save();

      // Load previous messages
      const messages = await Message.find({ room }).sort({ timestamp: 1 }).limit(50);
      socket.emit('messageHistory', messages);

      // Notify others
      socket.to(room).emit('userJoined', {
        username,
        timestamp: new Date(),
        message: `${username} has joined the room`
      });

      // Update users list
      const users = await User.find({ room, isOnline: true });
      io.to(room).emit('usersList', users.map(u => u.username));

    } catch (error) {
      console.error('Error joining room:', error);
      socket.emit('error', 'Failed to join room');
    }
  });

  // Handle new messages
  socket.on('sendMessage', async ({ username, room, message }) => {
    try {
      // Save message to database
      const newMessage = new Message({
        username,
        room,
        message
      });
      await newMessage.save();

      // Broadcast to room
      io.to(room).emit('newMessage', {
        username,
        message,
        timestamp: newMessage.timestamp
      });

    } catch (error) {
      console.error('Error sending message:', error);
      socket.emit('error', 'Failed to send message');
    }
  });

  // Handle typing indicator
  socket.on('typing', ({ username, room, isTyping }) => {
    socket.to(room).emit('userTyping', { username, isTyping });
  });

  // Handle disconnection
  socket.on('disconnect', async () => {
    try {
      const user = await User.findOneAndUpdate(
        { socketId: socket.id },
        { isOnline: false, lastSeen: new Date() }
      );

      if (user) {
        // Notify room
        socket.to(user.room).emit('userLeft', {
          username: user.username,
          timestamp: new Date(),
          message: `${user.username} has left the room`
        });

        // Update users list
        const users = await User.find({ room: user.room, isOnline: true });
        io.to(user.room).emit('usersList', users.map(u => u.username));
      }

    } catch (error) {
      console.error('Error handling disconnect:', error);
    }
  });
});

