// Operational Transformation (OT) implementation
class OTServer {
  constructor() {
    this.documentStates = new Map();
  }

  // Apply operation to document
  applyOperation(docId, operation, revision) {
    if (!this.documentStates.has(docId)) {
      this.documentStates.set(docId, {
        content: '',
        revision: 0,
        operations: []
      });
    }

    const doc = this.documentStates.get(docId);

    // Transform operation against concurrent operations
    const transformedOp = this.transformOperation(operation, doc.operations.slice(revision));

    // Apply transformed operation
    doc.content = this.applyToContent(doc.content, transformedOp);
    doc.operations.push(transformedOp);
    doc.revision++;

    return {
      operation: transformedOp,
      revision: doc.revision,
      content: doc.content
    };
  }

  transformOperation(operation, concurrentOps) {
    let transformedOp = { ...operation };

    for (const concurrentOp of concurrentOps) {
      transformedOp = this.transformAgainst(transformedOp, concurrentOp);
    }

    return transformedOp;
  }

  transformAgainst(op1, op2) {
    // Basic OT transformation for insert/delete operations
    if (op1.type === 'insert' && op2.type === 'insert') {
      if (op1.position < op2.position) {
        return op1;
      } else if (op1.position > op2.position) {
        return { ...op1, position: op1.position + op2.text.length };
      }
    }

    if (op1.type === 'insert' && op2.type === 'delete') {
      if (op1.position <= op2.position) {
        return op1;
      } else {
        return { ...op1, position: op1.position - op2.length };
      }
    }

    if (op1.type === 'delete' && op2.type === 'insert') {
      if (op1.position < op2.position) {
        return op1;
      } else {
        return { ...op1, position: op1.position + op2.text.length };
      }
    }

    if (op1.type === 'delete' && op2.type === 'delete') {
      if (op1.position < op2.position) {
        return op1;
      } else if (op1.position > op2.position + op2.length) {
        return { ...op1, position: op1.position - op2.length };
      }
    }

    return op1;
  }

  applyToContent(content, operation) {
    if (operation.type === 'insert') {
      return content.slice(0, operation.position) + operation.text + content.slice(operation.position);
    } else if (operation.type === 'delete') {
      return content.slice(0, operation.position) + content.slice(operation.position + operation.length);
    }
    return content;
  }
}

const otServer = new OTServer();

// Socket.io connection handler
io.on('connection', (socket) => {
  console.log('Client connected:', socket.id);

  let currentRoom = null;
  let username = null;

  // Join a code room
  socket.on('joinRoom', async ({ roomId, user }) => {
    try {
      username = user;
      currentRoom = roomId;

      socket.join(roomId);

      // Get room document from Redis
      const roomKey = `room:${roomId}`;
      let roomData = await redis.hgetall(roomKey);

      if (!roomData || !roomData.content) {
        roomData = {
          content: '',
          language: 'javascript',
          revision: 0,
          users: JSON.stringify([])
        };
      }

      // Add user to room
      const users = JSON.parse(roomData.users || '[]');
      const userIndex = users.findIndex(u => u.id === socket.id);
      if (userIndex === -1) {
        users.push({ id: socket.id, username: user, joinedAt: new Date() });
        await redis.hset(roomKey, 'users', JSON.stringify(users));
      }

      // Send current document state
      socket.emit('documentState', {
        content: roomData.content,
        language: roomData.language || 'javascript',
        revision: parseInt(roomData.revision) || 0
      });

      // Notify others
      socket.to(roomId).emit('userJoined', {
        id: socket.id,
        username: user,
        timestamp: new Date()
      });

      // Send user list
      io.to(roomId).emit('usersList', users);

    } catch (error) {
      console.error('Error joining room:', error);
      socket.emit('error', 'Failed to join room');
    }
  });

  // Handle text operations
  socket.on('textOperation', async ({ roomId, operation, revision }) => {
    try {
      const result = otServer.applyOperation(roomId, operation, revision);

      // Update Redis
      const roomKey = `room:${roomId}`;
      await redis.hset(roomKey, {
        content: result.content,
        revision: result.revision
      });

      // Broadcast to other users in room
      socket.to(roomId).emit('textOperation', {
        operation: result.operation,
        revision: result.revision,
        sender: socket.id
      });

      // Send acknowledgment to sender
      socket.emit('operationAck', {
        revision: result.revision
      });

    } catch (error) {
      console.error('Error processing operation:', error);
      socket.emit('error', 'Operation failed');
    }
  });

  // Handle language change
  socket.on('changeLanguage', async ({ roomId, language }) => {
    try {
      const roomKey = `room:${roomId}`;
      await redis.hset(roomKey, 'language', language);

      io.to(roomId).emit('languageChanged', {
        language,
        changedBy: username
      });
    } catch (error) {
      console.error('Error changing language:', error);
    }
  });

  // Execute code
  socket.on('executeCode', async ({ roomId, code, language }) => {
    try {
      socket.emit('executionStarted');

      const result = await executeCode(code, language);

      socket.emit('executionResult', result);

      // Broadcast to room if execution was successful
      if (!result.error) {
        socket.to(roomId).emit('codeExecuted', {
          code,
          result: result.output,
          executedBy: username
        });
      }

    } catch (error) {
      console.error('Error executing code:', error);
      socket.emit('executionResult', {
        error: 'Execution failed',
        output: error.message
      });
    }
  });

  // Cursor position updates
  socket.on('cursorMove', ({ roomId, position }) => {
    socket.to(roomId).emit('userCursorMove', {
      userId: socket.id,
      username,
      position
    });
  });

  // Selection updates
  socket.on('selectionChange', ({ roomId, selection }) => {
    socket.to(roomId).emit('userSelectionChange', {
      userId: socket.id,
      username,
      selection
    });
  });

  // Disconnect
  socket.on('disconnect', async () => {
    if (currentRoom) {
      try {
        const roomKey = `room:${currentRoom}`;
        const roomData = await redis.hgetall(roomKey);

        if (roomData && roomData.users) {
          const users = JSON.parse(roomData.users);
          const updatedUsers = users.filter(u => u.id !== socket.id);
          await redis.hset(roomKey, 'users', JSON.stringify(updatedUsers));

          socket.to(currentRoom).emit('userLeft', {
            id: socket.id,
            username,
            timestamp: new Date()
          });

          io.to(currentRoom).emit('usersList', updatedUsers);
        }
      } catch (error) {
        console.error('Error handling disconnect:', error);
      }
    }
  });
});

