// Trading Engine
class TradingEngine {
  constructor(dbPool) {
    this.db = dbPool;
  }

  async buyStock(userId, symbol, quantity, currentPrice) {
    const client = await this.db.connect();

    try {
      await client.query('BEGIN');

      // Get user balance
      const userResult = await client.query(
        'SELECT virtual_balance FROM users WHERE id = $1',
        [userId]
      );

      if (userResult.rows.length === 0) {
        throw new Error('User not found');
      }

      const userBalance = parseFloat(userResult.rows[0].virtual_balance);
      const totalCost = quantity * currentPrice;

      if (totalCost > userBalance) {
        throw new Error('Insufficient balance');
      }

      // Update user balance
      await client.query(
        'UPDATE users SET virtual_balance = virtual_balance - $1 WHERE id = $2',
        [totalCost, userId]
      );

      // Check if stock already in portfolio
      const portfolioResult = await client.query(
        'SELECT * FROM portfolios WHERE user_id = $1 AND symbol = $2',
        [userId, symbol]
      );

      if (portfolioResult.rows.length > 0) {
        // Update existing portfolio entry
        const existing = portfolioResult.rows[0];
        const newQuantity = parseFloat(existing.quantity) + quantity;
        const newTotalInvestment = parseFloat(existing.total_investment) + totalCost;
        const newAveragePrice = newTotalInvestment / newQuantity;

        await client.query(
          `UPDATE portfolios 
           SET quantity = $1, 
               average_price = $2, 
               total_investment = $3,
               updated_at = CURRENT_TIMESTAMP
           WHERE user_id = $4 AND symbol = $5`,
          [newQuantity, newAveragePrice, newTotalInvestment, userId, symbol]
        );
      } else {
        // Create new portfolio entry
        await client.query(
          `INSERT INTO portfolios 
           (user_id, symbol, quantity, average_price, total_investment)
           VALUES ($1, $2, $3, $4, $5)`,
          [userId, symbol, quantity, currentPrice, totalCost]
        );
      }

      // Record transaction
      await client.query(
        `INSERT INTO transactions 
         (user_id, symbol, type, quantity, price, total_amount)
         VALUES ($1, $2, 'BUY', $3, $4, $5)`,
        [userId, symbol, quantity, currentPrice, totalCost]
      );

      await client.query('COMMIT');

      return {
        success: true,
        message: `Successfully bought ${quantity} shares of ${symbol}`,
        remainingBalance: userBalance - totalCost
      };

    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async sellStock(userId, symbol, quantity, currentPrice) {
    const client = await this.db.connect();

    try {
      await client.query('BEGIN');

      // Check portfolio
      const portfolioResult = await client.query(
        'SELECT * FROM portfolios WHERE user_id = $1 AND symbol = $2',
        [userId, symbol]
      );

      if (portfolioResult.rows.length === 0) {
        throw new Error('Stock not in portfolio');
      }

      const portfolio = portfolioResult.rows[0];
      const currentQuantity = parseFloat(portfolio.quantity);

      if (quantity > currentQuantity) {
        throw new Error('Insufficient shares');
      }

      const totalValue = quantity * currentPrice;

      // Update or remove from portfolio
      if (quantity === currentQuantity) {
        // Remove completely
        await client.query(
          'DELETE FROM portfolios WHERE user_id = $1 AND symbol = $2',
          [userId, symbol]
        );
      } else {
        // Update quantity
        const newQuantity = currentQuantity - quantity;
        const newTotalInvestment = parseFloat(portfolio.total_investment) * (newQuantity / currentQuantity);

        await client.query(
          `UPDATE portfolios 
           SET quantity = $1, 
               total_investment = $2,
               updated_at = CURRENT_TIMESTAMP
           WHERE user_id = $3 AND symbol = $4`,
          [newQuantity, newTotalInvestment, userId, symbol]
        );
      }

      // Update user balance
      await client.query(
        'UPDATE users SET virtual_balance = virtual_balance + $1 WHERE id = $2',
        [totalValue, userId]
      );

      // Record transaction
      await client.query(
        `INSERT INTO transactions 
         (user_id, symbol, type, quantity, price, total_amount)
         VALUES ($1, $2, 'SELL', $3, $4, $5)`,
        [userId, symbol, quantity, currentPrice, totalValue]
      );

      await client.query('COMMIT');

      return {
        success: true,
        message: `Successfully sold ${quantity} shares of ${symbol}`,
        proceeds: totalValue
      };

    } catch (error) {
      await client.query('ROLLBACK');
      throw error;
    } finally {
      client.release();
    }
  }

  async getPortfolioValue(userId) {
    try {
      const portfolioResult = await this.db.query(
        'SELECT * FROM portfolios WHERE user_id = $1',
        [userId]
      );

      let totalValue = 0;
      const portfolio = [];

      for (const row of portfolioResult.rows) {
        // Get current price for each stock
        const priceData = await stockFetcher.getRealTimePrice(row.symbol);
        const currentValue = row.quantity * priceData.price;
        totalValue += currentValue;

        portfolio.push({
          symbol: row.symbol,
          quantity: row.quantity,
          averagePrice: row.average_price,
          currentPrice: priceData.price,
          totalInvestment: row.total_investment,
          currentValue: currentValue,
          profitLoss: currentValue - row.total_investment,
          profitLossPercent: ((currentValue - row.total_investment) / row.total_investment) * 100
        });
      }

      // Get user balance
      const userResult = await this.db.query(
        'SELECT virtual_balance FROM users WHERE id = $1',
        [userId]
      );

      const cashBalance = userResult.rows[0]?.virtual_balance || 0;
      const totalNetWorth = totalValue + parseFloat(cashBalance);

      return {
        portfolio,
        cashBalance,
        stockValue: totalValue,
        totalNetWorth,
        lastUpdated: new Date()
      };

    } catch (error) {
      console.error('Error calculating portfolio value:', error);
      throw error;
    }
  }
}

