// WebSocket server for real-time data
const connectedClients = new Map();

wss.on('connection', (ws, req) => {
  console.log('New WebSocket connection');

  ws.on('message', async (message) => {
    try {
      const data = JSON.parse(message);

      switch (data.type) {
        case 'subscribe':
          // Subscribe to stock updates
          if (data.symbols && Array.isArray(data.symbols)) {
            connectedClients.set(ws, data.symbols);

            // Send initial prices
            for (const symbol of data.symbols) {
              try {
                const priceData = await stockFetcher.getRealTimePrice(symbol);
                ws.send(JSON.stringify({
                  type: 'price_update',
                  symbol,
                  data: priceData,
                  timestamp: new Date()
                }));
              } catch (error) {
                console.error(`Error fetching ${symbol}:`, error);
              }
            }

            // Start periodic updates
            const updateInterval = setInterval(async () => {
              if (connectedClients.has(ws)) {
                const symbols = connectedClients.get(ws);
                for (const symbol of symbols) {
                  try {
                    const priceData = await stockFetcher.getRealTimePrice(symbol);
                    ws.send(JSON.stringify({
                      type: 'price_update',
                      symbol,
                      data: priceData,
                      timestamp: new Date()
                    }));
                  } catch (error) {
                    console.error(`Error updating ${symbol}:`, error);
                  }
                }
              }
            }, 5000); // Update every 5 seconds

            // Store interval for cleanup
            ws.updateInterval = updateInterval;
          }
          break;

        case 'unsubscribe':
          if (connectedClients.has(ws)) {
            connectedClients.delete(ws);
          }
          break;
      }

    } catch (error) {
      console.error('Error processing WebSocket message:', error);
    }
  });

  ws.on('close', () => {
    console.log('WebSocket disconnected');
    if (connectedClients.has(ws)) {
      connectedClients.delete(ws);
    }
    if (ws.updateInterval) {
      clearInterval(ws.updateInterval);
    }
  });
});

