// AI Service Classes
class AIContentGenerator {
  constructor(openaiClient) {
    this.openai = openaiClient;
  }

  async generateContent(prompt, options = {}) {
    try {
      const cacheKey = `ai_content:${Buffer.from(prompt).toString('base64')}`;
      const cached = await redisClient.get(cacheKey);

      if (cached) {
        return JSON.parse(cached);
      }

      const completion = await this.openai.chat.completions.create({
        model: options.model || 'gpt-4',
        messages: [
          {
            role: 'system',
            content: 'You are a professional content writer. Generate engaging, SEO-friendly content.'
          },
          {
            role: 'user',
            content: prompt
          }
        ],
        max_tokens: options.maxTokens || 1000,
        temperature: options.temperature || 0.7
      });

      const generatedText = completion.choices[0].message.content;

      const result = {
        content: generatedText,
        tokensUsed: completion.usage.total_tokens,
        model: completion.model
      };

      // Cache for 1 hour
      await redisClient.setEx(cacheKey, 3600, JSON.stringify(result));

      return result;

    } catch (error) {
      console.error('Error generating AI content:', error);
      throw error;
    }
  }

  async generateSeoMeta(title, content) {
    const prompt = `Generate SEO meta title and description for the following content:
Title: ${title}
Content: ${content.substring(0, 500)}...

Provide response in JSON format: {\"metaTitle\": \"...\", \"metaDescription\": \"...\", \"keywords\": [\"...\"]}`;

    try {
      const completion = await this.openai.chat.completions.create({
        model: 'gpt-3.5-turbo',
        messages: [{
          role: 'user',
          content: prompt
        }],
        response_format: { type: 'json_object' }
      });

      return JSON.parse(completion.choices[0].message.content);
    } catch (error) {
      console.error('Error generating SEO meta:', error);
      return {
        metaTitle: title,
        metaDescription: content.substring(0, 160),
        keywords: []
      };
    }
  }
}

class TextAnalyzer {
  constructor() {
    this.tokenizer = new natural.WordTokenizer();
    this.stemmer = natural.PorterStemmer;
    this.sentiment = new natural.SentimentAnalyzer('English', natural.PorterStemmer, 'afinn');
  }

  analyzeSentiment(text) {
    const tokens = this.tokenizer.tokenize(text.toLowerCase());
    const score = this.sentiment.getSentiment(tokens);

    let sentiment = 'neutral';
    if (score > 0.2) sentiment = 'positive';
    else if (score < -0.2) sentiment = 'negative';

    return {
      sentiment,
      score: parseFloat(score.toFixed(3))
    };
  }

  extractKeywords(text, maxKeywords = 10) {
    const tokens = this.tokenizer.tokenize(text.toLowerCase());
    const filteredTokens = tokens.filter(token => 
      token.length > 3 && !natural.stopwords.includes(token)
    );

    const stemmedTokens = filteredTokens.map(token => this.stemmer.stem(token));

    // Simple frequency analysis
    const frequency = {};
    stemmedTokens.forEach(token => {
      frequency[token] = (frequency[token] || 0) + 1;
    });

    // Sort by frequency and get top keywords
    const sortedKeywords = Object.entries(frequency)
      .sort((a, b) => b[1] - a[1])
      .slice(0, maxKeywords)
      .map(([keyword]) => keyword);

    return sortedKeywords;
  }

  calculateReadability(text) {
    // Simple readability score based on sentence and word length
    const sentences = text.split(/[.!?]+/).filter(s => s.trim().length > 0);
    const words = text.split(/\s+/).filter(w => w.length > 0);

    if (sentences.length === 0 || words.length === 0) {
      return {
        score: 0,
        level: 'Unknown'
      };
    }

    const wordsPerSentence = words.length / sentences.length;
    const syllables = words.reduce((count, word) => count + this.countSyllables(word), 0);
    const syllablesPerWord = syllables / words.length;

    // Flesch Reading Ease score
    const fleschScore = 206.835 - (1.015 * wordsPerSentence) - (84.6 * syllablesPerWord);

    let level = 'Standard';
    if (fleschScore >= 90) level = 'Very Easy';
    else if (fleschScore >= 80) level = 'Easy';
    else if (fleschScore >= 70) level = 'Fairly Easy';
    else if (fleschScore >= 60) level = 'Standard';
    else if (fleschScore >= 50) level = 'Fairly Difficult';
    else if (fleschScore >= 30) level = 'Difficult';
    else level = 'Very Difficult';

    return {
      score: Math.round(fleschScore),
      level
    };
  }

  countSyllables(word) {
    word = word.toLowerCase();
    if (word.length <= 3) return 1;
    word = word.replace(/(?:[^laeiouy]es|ed|[^laeiouy]e)$/, '');
    word = word.replace(/^y/, '');
    const syllables = word.match(/[aeiouy]{1,2}/g);
    return syllables ? syllables.length : 1;
  }
}

