// Content Management
app.post('/api/content', authenticateJWT, checkRole(['admin', 'editor']), async (req, res) => {
  try {
    const { title, content, category, tags, generateSeo = true } = req.body;

    // Generate slug from title
    const slug = title.toLowerCase()
      .replace(/[^\w\s]/gi, '')
      .replace(/\s+/g, '-')
      .substring(0, 100);

    // Analyze content
    const analysis = {
      sentiment: textAnalyzer.analyzeSentiment(content),
      keywords: textAnalyzer.extractKeywords(content),
      readability: textAnalyzer.calculateReadability(content),
      generatedByAI: req.body.generatedByAI || false
    };

    let seoData = {};
    if (generateSeo) {
      seoData = await aiGenerator.generateSeoMeta(title, content);
      seoData.readabilityScore = analysis.readability.score;
    }

    const newContent = new Content({
      title,
      slug,
      content,
      author: req.user.userId,
      category,
      tags,
      seo: seoData,
      aiAnalysis: analysis,
      revisions: [{
        content,
        editedBy: req.user.userId,
        changes: 'Initial creation'
      }]
    });

    await newContent.save();

    // Invalidate cache
    await redisClient.del('recent_content');

    res.json({
      id: newContent._id,
      slug: newContent.slug,
      title: newContent.title,
      status: newContent.status,
      analysis: newContent.aiAnalysis,
      seo: newContent.seo
    });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
