app.put('/api/content/:id/improve', authenticateJWT, checkRole(['admin', 'editor']), async (req, res) => {
  try {
    const contentId = req.params.id;
    const { improvements = [] } = req.body;

    const content = await Content.findById(contentId);
    if (!content) {
      return res.status(404).json({ error: 'Content not found' });
    }

    // Check permissions
    if (content.author.toString() !== req.user.userId && req.user.role !== 'admin') {
      return res.status(403).json({ error: 'Not authorized to edit this content' });
    }

    let improvedContent = content.content;
    const improvementsApplied = [];

    // Apply AI improvements
    for (const improvement of improvements) {
      switch (improvement.type) {
        case 'expand':
          const expansionPrompt = `Expand and elaborate on this section while maintaining the original meaning:\n\n${improvement.text}`;
          const expansion = await aiGenerator.generateContent(expansionPrompt, { maxTokens: 300 });
          improvedContent = improvedContent.replace(improvement.text, expansion.content);
          improvementsApplied.push('Expanded section');
          break;

        case 'simplify':
          const simplifyPrompt = `Simplify this text to make it more readable:\n\n${improvement.text}`;
          const simplified = await aiGenerator.generateContent(simplifyPrompt, { maxTokens: 200 });
          improvedContent = improvedContent.replace(improvement.text, simplified.content);
          improvementsApplied.push('Simplified language');
          break;

        case 'seo_optimize':
          // Add keywords naturally
          const seoPrompt = `Rewrite this paragraph to naturally include these keywords: ${improvement.keywords.join(', ')}:\n\n${improvement.text}`;
          const seoOptimized = await aiGenerator.generateContent(seoPrompt, { maxTokens: 250 });
          improvedContent = improvedContent.replace(improvement.text, seoOptimized.content);
          improvementsApplied.push('SEO optimization');
          break;
      }
    }

    // Update content
    content.content = improvedContent;
    content.revisions.push({
      content: improvedContent,
      editedBy: req.user.userId,
      changes: `AI improvements applied: ${improvementsApplied.join(', ')}`
    });
    content.updatedAt = new Date();

    // Re-analyze content
    content.aiAnalysis = {
      sentiment: textAnalyzer.analyzeSentiment(improvedContent),
      keywords: textAnalyzer.extractKeywords(improvedContent),
      readability: textAnalyzer.calculateReadability(improvedContent),
      generatedByAI: true
    };

    await content.save();

    res.json({
      id: content._id,
      content: content.content,
      improvementsApplied,
      analysis: content.aiAnalysis
    });
  } catch (error) {
    res.status(400).json({ error: error.message });
  }
});

