// Geofence Manager
class GeofenceManager {
  constructor() {
    this.geofences = new Map();
    this.loadGeofences();
  }

  async loadGeofences() {
    try {
      const fences = await Geofence.find({ isActive: true });
      this.geofences.clear();

      fences.forEach(fence => {
        this.geofences.set(fence._id.toString(), fence);
      });

      console.log(`Loaded ${this.geofences.size} active geofences`);
    } catch (error) {
      console.error('Error loading geofences:', error);
    }
  }

  async checkGeofences(vehicleId, location) {
    const alerts = [];

    for (const [fenceId, fence] of this.geofences) {
      let isInside = false;

      if (fence.type === 'circle') {
        const center = fence.coordinates[0];
        const radius = fence.radius || 100; // meters

        isInside = geolib.isPointWithinRadius(
          { latitude: location[1], longitude: location[0] },
          { latitude: center[1], longitude: center[0] },
          radius
        );
      } else if (fence.type === 'polygon') {
        // Convert polygon coordinates for geolib
        const polygon = fence.coordinates.map(coord => ({
          latitude: coord[1],
          longitude: coord[0]
        }));

        isInside = geolib.isPointInPolygon(
          { latitude: location[1], longitude: location[0] },
          polygon
        );
      }

      // Check if we need to create an alert
      const vehicleKey = `vehicle:${vehicleId}:geofence:${fenceId}`;
      const wasInside = await redisClient.get(vehicleKey);

      if (isInside && (!wasInside || wasInside === 'outside')) {
        // Vehicle entered geofence
        if (fence.alertOn === 'enter' || fence.alertOn === 'both') {
          alerts.push({
            type: 'geofence_enter',
            message: `Vehicle entered geofence: ${fence.name}`,
            fenceId: fence._id,
            fenceName: fence.name
          });
        }
        await redisClient.set(vehicleKey, 'inside');
      } else if (!isInside && wasInside === 'inside') {
        // Vehicle exited geofence
        if (fence.alertOn === 'exit' || fence.alertOn === 'both') {
          alerts.push({
            type: 'geofence_exit',
            message: `Vehicle exited geofence: ${fence.name}`,
            fenceId: fence._id,
            fenceName: fence.name
          });
        }
        await redisClient.set(vehicleKey, 'outside');
      }
    }

    return alerts;
  }

  async addGeofence(fenceData) {
    const fence = new Geofence(fenceData);
    await fence.save();
    this.geofences.set(fence._id.toString(), fence);
    return fence;
  }
}

