// Route Optimizer
class RouteOptimizer {
  constructor() {
    // This would typically integrate with routing APIs like Google Directions, OSRM, etc.
  }

  async optimizeRoute(waypoints, options = {}) {
    try {
      // For demo, use a simple algorithm or integrate with external API
      // In production, use Google Maps Directions API or OSRM

      const optimizedWaypoints = this.nearestNeighbor(waypoints);

      // Calculate total distance
      let totalDistance = 0;
      for (let i = 0; i < optimizedWaypoints.length - 1; i++) {
        totalDistance += this.calculateDistance(
          optimizedWaypoints[i],
          optimizedWaypoints[i + 1]
        );
      }

      // Estimate time based on average speed
      const averageSpeed = options.averageSpeed || 40; // km/h
      const estimatedTime = totalDistance / averageSpeed; // hours

      return {
        waypoints: optimizedWaypoints,
        totalDistance: totalDistance.toFixed(2),
        estimatedTime: (estimatedTime * 60).toFixed(0), // minutes
        optimizationMethod: 'nearest_neighbor'
      };
    } catch (error) {
      console.error('Error optimizing route:', error);
      throw error;
    }
  }

  nearestNeighbor(waypoints) {
    if (waypoints.length <= 1) return waypoints;

    const unvisited = [...waypoints];
    const route = [unvisited.shift()]; // Start with first waypoint

    while (unvisited.length > 0) {
      const lastPoint = route[route.length - 1];
      let nearestIndex = 0;
      let nearestDistance = Infinity;

      for (let i = 0; i < unvisited.length; i++) {
        const distance = this.calculateDistance(lastPoint, unvisited[i]);
        if (distance < nearestDistance) {
          nearestDistance = distance;
          nearestIndex = i;
        }
      }

      route.push(unvisited.splice(nearestIndex, 1)[0]);
    }

    return route;
  }

  calculateDistance(point1, point2) {
    // Haversine formula for distance between two coordinates
    const [lon1, lat1] = point1;
    const [lon2, lat2] = point2;

    const R = 6371; // Earth's radius in km
    const dLat = this.toRad(lat2 - lat1);
    const dLon = this.toRad(lon2 - lon1);
    const a = 
      Math.sin(dLat / 2) * Math.sin(dLat / 2) +
      Math.cos(this.toRad(lat1)) * Math.cos(this.toRad(lat2)) * 
      Math.sin(dLon / 2) * Math.sin(dLon / 2);
    const c = 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));

    return R * c; // Distance in km
  }

  toRad(degrees) {
    return degrees * (Math.PI / 180);
  }
}

const routeOptimizer = new RouteOptimizer();

// Socket.io for real-time tracking
io.on('connection', (socket) => {
  console.log('Tracking client connected:', socket.id);

  // Join vehicle room for updates
  socket.on('subscribeVehicle', (vehicleId) => {
    socket.join(`vehicle:${vehicleId}`);
    console.log(`Client ${socket.id} subscribed to vehicle ${vehicleId}`);
  });

  // Unsubscribe from vehicle
  socket.on('unsubscribeVehicle', (vehicleId) => {
    socket.leave(`vehicle:${vehicleId}`);
    console.log(`Client ${socket.id} unsubscribed from vehicle ${vehicleId}`);
  });

  // Handle location updates from vehicles/devices
  socket.on('locationUpdate', async (data) => {
    try {
      const { vehicleId, location, speed, heading, accuracy, batteryLevel, metadata } = data;

      // Validate location data
      if (!vehicleId || !location || location.length !== 2) {
        console.error('Invalid location data:', data);
        return;
      }

      const [longitude, latitude] = location;

      // Update vehicle current location
      const vehicle = await Vehicle.findOneAndUpdate(
        { vehicleId },
        {
          currentLocation: {
            type: 'Point',
            coordinates: [longitude, latitude]
          },
          speed: speed || 0,
          heading: heading || 0,
          lastUpdated: new Date(),
          status: 'active',
          $set: {
            'metadata.fuelLevel': metadata?.fuelLevel,
            'metadata.odometer': metadata?.odometer,
            'metadata.temperature': metadata?.temperature
          }
        },
        { new: true, upsert: false }
      );

      if (!vehicle) {
        console.error(`Vehicle ${vehicleId} not found`);
        return;
      }

      // Save location history
      const locationRecord = new LocationHistory({
        vehicleId,
        location: {
          type: 'Point',
          coordinates: [longitude, latitude]
        },
        speed,
        heading,
        accuracy,
        batteryLevel,
        metadata
      });

      await locationRecord.save();

      // Check geofences
      const geofenceAlerts = await geofenceManager.checkGeofences(vehicleId, location);

      // Create alerts if any
      for (const alertData of geofenceAlerts) {
        const alert = new Alert({
          vehicleId,
          type: alertData.type,
          message: alertData.message,
          location: {
            type: 'Point',
            coordinates: location
          },
          severity: 'medium',
          isAcknowledged: false
        });

        await alert.save();

        // Broadcast alert
        io.emit('newAlert', {
          ...alert.toObject(),
          fenceName: alertData.fenceName
        });
      }

      // Check for speed alerts
      if (speed > 100) { // 100 km/h threshold
        const speedAlert = new Alert({
          vehicleId,
          type: 'speed',
          message: `Vehicle exceeding speed limit: ${speed} km/h`,
          location: {
            type: 'Point',
            coordinates: location
          },
          severity: 'high',
          isAcknowledged: false
        });

        await speedAlert.save();
        io.emit('newAlert', speedAlert.toObject());
      }

      // Broadcast location update to subscribed clients
      const updateData = {
        vehicleId,
        location: [longitude, latitude],
        speed,
        heading,
        timestamp: new Date(),
        vehicleName: vehicle.name,
        licensePlate: vehicle.licensePlate
      };

      io.to(`vehicle:${vehicleId}`).emit('vehicleUpdate', updateData);

      // Also emit to admin/dispatcher rooms
      io.to('admin').emit('vehicleUpdate', updateData);
      io.to('dispatcher').emit('vehicleUpdate', updateData);

      // Update Redis cache
      const redisKey = `vehicle:${vehicleId}:location`;
      await redisClient.setEx(redisKey, 60, JSON.stringify(updateData)); // Cache for 60 seconds

    } catch (error) {
      console.error('Error processing location update:', error);
    }
  });

  // Handle vehicle status changes
  socket.on('vehicleStatus', async (data) => {
    try {
      const { vehicleId, status, driverId } = data;

      const update = { status, lastUpdated: new Date() };
      if (driverId) update.driver = driverId;

      const vehicle = await Vehicle.findOneAndUpdate(
        { vehicleId },
        update,
        { new: true }
      );

      if (vehicle) {
        io.emit('vehicleStatusChanged', {
          vehicleId,
          status,
          vehicleName: vehicle.name,
          timestamp: new Date()
        });
      }
    } catch (error) {
      console.error('Error updating vehicle status:', error);
    }
  });

  // Join admin/dispatcher rooms
  socket.on('joinRole', (role) => {
    if (['admin', 'dispatcher'].includes(role)) {
      socket.join(role);
      console.log(`Client ${socket.id} joined ${role} room`);
    }
  });
});

